def dfs_recursive(graph, start_node, visited=None):
    if visited is None:
        visited = set()

    visited.add(start_node)
    print(start_node, end=' ')

    for neighbor in graph[start_node]:
        if neighbor not in visited:
            dfs_recursive(graph, neighbor, visited)


def dfs_iterative(graph, start_node):
    visited = set()
    stack = [start_node]

    while stack:
        node = stack.pop()
        if node not in visited:
            visited.add(node)
            print(node, end=' ')

            # Explore neighbors. To mimic the recursive order (e.g., A->B->D),
            # push neighbors in reverse order of their appearance in the adjacency list.
            # This ensures the first neighbor in the list is processed first
            # (since it's pushed last onto the stack, it will be popped first).
            for neighbor in reversed(graph[node]):
                if neighbor not in visited:
                    stack.append(neighbor)


